window.EXPRESSION_SCRIPT={POSTFIX:{START:e=>`Let's evaluate the postfix expression: ${e}. We'll scan it from left to right, using a stack to keep track of our numbers!`,NUMBER:e=>`Found a number: ${e}. Into the stack it goes!`,OPERATOR:e=>`Spotted an operator: ${e}. Time to do some math! We'll pop the top two numbers from our stack.`,CALC:(e,t,n,r)=>`Calculating ${e} ${n} ${t}. The result is ${r}. Let's push that back onto the stack!`,SUCCESS:e=>`We've reached the end! The only number left in our stack is ${e}. That's our answer!`},PREFIX:{START:e=>`Let's solve this prefix expression: ${e}. For prefix, it's easier to scan from right to left. Grab your stack, here we go!`,NUMBER:e=>`Found number ${e}. Pushing it onto the stack.`,OPERATOR:e=>`Operator ${e} found! Let's take the top two numbers from our stack and apply it.`,CALC:(e,t,n,r)=>`Operating ${e} ${n} ${t} gives us ${r}. Back into the stack it goes!`,SUCCESS:e=>`Scanning complete! The final survivor in our stack is ${e}. Puzzle solved!`},INFIX:{START:e=>`Infix evaluation time: ${e}. This is tricky because we have to respect operator precedence and parentheses! We'll use two stacks: one for numbers and one for operators.`,NUMBER:e=>`A number! ${e} goes into the operand stack.`,OPEN_PAREN:()=>`An open parenthesis! This starts a high-priority sub-problem. Into the operator stack!`,CLOSE_PAREN:()=>`Closing parenthesis! Let's solve everything inside until we hit the opening bracket.`,OPERATOR:e=>`Operator ${e} found. If the top operator in our stack is more important, we'll solve that one first!`,CALC:(e,t,n,r)=>`Popping ${e} and ${t} to apply ${n}. Result ${r} goes to the number stack.`,SUCCESS:e=>`All tokens processed and all operators applied. Our final answer is ${e}!`}};